    private func performPasswordReset(newPassword: String) {
        setLoading(true)
        
        guard let url = URL(string: "https://api.myapp.com/reset-password") else {
            setLoading(false)
            showAlert(title: "Error", message: "Invalid API endpoint")
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = [
            "token": token,
            "newPassword": newPassword
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.setLoading(false)
                
                if let error = error {
                    self?.showAlert(title: "Error", message: error.localizedDescription)
                    return
                }
                
                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.showAlert(title: "Error", message: "Invalid response")
                    return
                }
                
                if httpResponse.statusCode == 200 {
                    self?.showSuccessAndDismiss()
                } else {
                    var message = "Failed to reset password"
                    if let data = data,
                       let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                       let errorMessage = json["message"] as? String {
                        message = errorMessage
                    }
                    self?.showAlert(title: "Error", message: message)
                }
            }
        }.resume()
    }
    
